    '41a52d28-c6f3-4ddd-8f7d-2a7c1ca88dc5',
    'maps-elicitprovideelicit-011',
    'Module 11: Giving Information, Advice & Feedback',
    'Building Rapport',
    'advanced',
    8,
    'Ask permission before sharing information or advice; Build on what the person already knows; Keep information brief and neutral; Invite their interpretation',
    'A colleague asks about the promotion process. Practice sharing information collaboratively using the Elicit-Provide-Elicit approach.',
    '{"name": "Tom", "role": "colleague", "background": "Team member interested in promotion but unfamiliar with the process. Asking for guidance.", "personality_traits": ["curious", "motivated", "uncertain", "eager"], "tone_spectrum": {"word_complexity": 0.4, "sentence_length": 0.4, "emotional_expressiveness": 0.4, "disclosure_level": 0.4, "response_latency": 0.4, "confidence_level": 0.4}, "starting_tone_position": 0.4, "triggers": ["condescension", "lecturing", "dismissiveness"], "comfort_topics": ["autonomy", "clarity", "support", "growth"]}'::jsonb,
    '{"start_node_id": "info_1", "nodes": {"info_1": {"id": "info_1", "persona_text": "I''m thinking about applying for the specialist role, but I''m not really sure what the process involves. What should I do?", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_info_1_0", "option_text": "First, you need to update your CV and submit it through the HR portal. Then there''s a two-stage interview process. You should also prepare a portfolio of your work. The evidence clearly shows that candidates who do all this have the best chance.", "preview_hint": "Directive approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This jumps straight to telling without first exploring what they know or asking permission.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2a", "exploration_depth": "surface"}, {"id": "cp_info_1_1", "option_text": "I''d be happy to share some information about that. First, what do you already know about the promotion process - what have you heard or seen before?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["permission", "elicit"], "competency_links": ["A6"], "feedback": {"immediate": "Perfect - accepts the request and starts by eliciting what they already know.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2b", "exploration_depth": "surface"}, {"id": "cp_info_1_2", "option_text": "It''s really about being prepared. If you''re not ready, you shouldn''t apply.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This provides judgmental feedback that will likely create defensiveness.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_2a": {"id": "info_2a", "persona_text": "I know all that. It''s not like I''m stupid. I just can''t seem to figure out the right approach.", "persona_mood": "withdrawn_disengaged", "themes": ["Resistance", "Barriers"], "choice_points": [{"id": "cp_info_2a_0", "option_text": "I didn''t say you were stupid. I''m just trying to help. You asked me what to do.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This becomes argumentative and damages the relationship further.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_poor", "exploration_depth": "surface"}, {"id": "cp_info_2a_1", "option_text": "You''re right, I jumped in too quickly. You''ve clearly been thinking about this. What''s your understanding been so far about the process?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery - practitioner takes responsibility and pivots to eliciting.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_2b": {"id": "info_2b", "persona_text": "Well, I know there''s an application form, and then interviews. I think I need to provide examples of my work. I''ve seen people go through it, but I''m not clear on the timeline or what exactly they''re looking for.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [{"id": "cp_info_2b_0", "option_text": "Right, so you understand the basics - application, interviews, work examples. Would it be helpful if I shared some information about the timeline and what the panel typically looks for?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.1, "technique_tags": ["reflection", "permission"], "competency_links": ["A6"], "feedback": {"immediate": "Excellent - acknowledges what they know and explicitly asks permission before providing information.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_3a", "exploration_depth": "surface"}, {"id": "cp_info_2b_1", "option_text": "The timeline is 4-6 weeks from application to decision. You should start preparing immediately.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This gives directive advice without permission or exploring alternatives.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2a", "exploration_depth": "surface"}, {"id": "cp_info_2b_2", "option_text": "You need to understand this better or you won''t succeed. Let me explain everything.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This belittles them and takes an expert-superior position.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_3a": {"id": "info_3a", "persona_text": "Yes, I''d appreciate that. I want to make sure I approach this the right way.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_info_3a_0", "option_text": "The process typically takes 4-6 weeks. After submitting your application, there''s usually a screening interview, then a panel interview with the hiring manager and a peer. The panel looks for both technical expertise and leadership potential. They''ll want specific examples of how you''ve handled complex situations and supported colleagues.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.1, "technique_tags": ["provide_info"], "competency_links": ["B1"], "feedback": {"immediate": "Good - provides information neutrally, briefly, and without being prescriptive.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_4a", "exploration_depth": "surface"}, {"id": "cp_info_3a_1", "option_text": "The process is rigorous. Most people who apply don''t get it. You really need to prepare extensively. Let me give you a detailed breakdown of every step, including common pitfalls, question types, scoring rubrics, and what to wear...", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This provides too much information, is overly prescriptive, and doesn''t check understanding.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_4a": {"id": "info_4a", "persona_text": "That''s helpful. So 4-6 weeks total, and they want both technical and leadership examples. That gives me a clearer picture of what to prepare.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_info_4a_0", "option_text": "What do you make of that information? How does it shape your thinking about preparing?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["elicit"], "competency_links": ["B6"], "feedback": {"immediate": "Perfect - invites their interpretation and returns control to them.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_5a", "exploration_depth": "surface"}, {"id": "cp_info_4a_1", "option_text": "Yes, that''s exactly right. You should focus on leadership examples mostly.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This tells them what to think rather than eliciting their perspective.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_2a", "exploration_depth": "surface"}, {"id": "cp_info_4a_2", "option_text": "There''s a lot more detail I should add. Let me explain the scoring system...", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dumps more information without checking how the first information was received.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_5a": {"id": "info_5a", "persona_text": "It makes me feel more prepared knowing what to expect. I can start gathering my examples now - maybe situations where I helped resolve a difficult case or supported a new team member. The 4-6 week timeline gives me time to prepare properly rather than rushing.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_info_5a_0", "option_text": "You''re already thinking about specific examples that would demonstrate your expertise and leadership. The timeline gives you space to prepare thoughtfully. What feels most important to focus on first?", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["affirmation", "open_question"], "competency_links": ["A6"], "feedback": {"immediate": "Excellent - affirms their application and continues collaborative exploration.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_good", "exploration_depth": "surface"}, {"id": "cp_info_5a_1", "option_text": "You should focus on leadership examples first. Those carry the most weight.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This loads on more directives instead of staying with their understanding.", "learning_note": "Continue practicing MI techniques to build your coaching skills."}, "next_node_id": "info_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "info_end_good": {"id": "info_end_good", "persona_text": "I think I should start by documenting my recent cases - maybe 3-4 strong examples. Then I can practice articulating what I did and why it worked. Having this information really helps me approach this more strategically.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Change"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "info_end_poor": {"id": "info_end_poor", "persona_text": "I feel more confused now than when I started. Maybe I should just figure this out on my own.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}}}'::jsonb,
    ARRAY'["B1", "B2", "B6", "A2", "A6", "A1"]',
